npx tsx -e "
import { StateManager } from './src/lib/workflow/state-manager.ts';
import { parseAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { performScopeAssessment, convertSettingsToConfig } from './src/lib/scope/index.ts';
import { getSettings } from './src/lib/settings.ts';

const issueBody = \`## Acceptance Criteria
- [ ] **AC-1:** New RunOrchestrator class
- [ ] **AC-2:** run.ts becomes thin adapter
- [ ] **AC-3:** typed RunConfig
- [ ] **AC-4:** importable without CLI
- [ ] **AC-5:** ConfigResolver extracted
- [ ] **AC-6:** tests pass
- [ ] **AC-7:** normalizeCommanderOptions eliminated\`;

const issueTitle = 'arch: extract RunOrchestrator';

(async () => {
  const settings = await getSettings();
  const config = convertSettingsToConfig(settings.scopeAssessment);
  const criteria = parseAcceptanceCriteria(issueBody);
  const assessment = performScopeAssessment(criteria, issueBody, issueTitle, config);
  const manager = new StateManager();
  await manager.updateScopeAssessment(503, assessment);
  console.log('Scope assessment stored');
})();
" 2>&1
